typescript_interfaces.BaseResponse:
interface BaseResponse {
  success: boolean;
  error?: ErrorDetail;
  timestamp: string;
  generated_at: string;
  cache_expires_at?: string;
}

typescript_interfaces.ErrorDetail:
interface ErrorDetail {
  code: string;
  message: string;
  details?: Record<string, unknown>;
}

typescript_interfaces.PaginationMeta:
interface PaginationMeta {
  page: number;
  limit: number;
  total_count: number;
  total_pages: number;
  has_next_page: boolean;
  has_prev_page: boolean;
}

typescript_interfaces.OverviewResponse:
interface OverviewResponse extends BaseResponse {
  data: {
    database: DatabaseInfo;
    statistics: DatabaseStatistics;
    modules: ModuleSummary;
    anomalies: AnomalySummary;
    health_score: HealthScore;
    top_modules_by_size: TopModule[];
    top_largest_tables: LargestTable[];
  };
}

typescript_interfaces.DatabaseInfo:
interface DatabaseInfo {
  name: string;
  server_version: string;
  charset: string;
  collation: string;
}

typescript_interfaces.DatabaseStatistics:
interface DatabaseStatistics {
  total_tables: number;
  total_rows: number;
  total_size_bytes: number;
  total_size_human: string;
  data_size_bytes: number;
  index_size_bytes: number;
  total_columns: number;
  engine_types: string[];
}

typescript_interfaces.ModuleSummary:
interface ModuleSummary {
  count: number;
  distribution: ModuleDistribution[];
}

typescript_interfaces.ModuleDistribution:
interface ModuleDistribution {
  name: string;
  table_count: number;
  size_percentage: number;
}

typescript_interfaces.AnomalySummary:
interface AnomalySummary {
  total: number;
  critical: number;
  warning: number;
  info: number;
  by_category: Record<string, number>;
}

typescript_interfaces.HealthScore:
interface HealthScore {
  overall: number;
  breakdown: {
    primary_key_health: number;
    index_health: number;
    table_usage_health: number;
  };
  grade: string;
  recommendation: string;
}

typescript_interfaces.TopModule:
interface TopModule {
  name: string;
  description_th: string;
  description_en: string;
  total_rows: number;
  total_size_bytes: number;
  size_mb: number;
  size_gb: number;
  size_percentage: number;
}

typescript_interfaces.LargestTable:
interface LargestTable {
  name: string;
  module: string;
  rows: number;
  size_mb: number;
}

typescript_interfaces.ModulesListResponse:
interface ModulesListResponse extends BaseResponse {
  data: {
    modules: ModuleDetail[];
    total_count: number;
    statistics: {
      average_table_count: number;
      average_size_gb: number;
      total_anomaly_count: number;
    };
  };
}

typescript_interfaces.ModuleDetail:
interface ModuleDetail {
  name: string;
  description_th: string;
  description_en: string;
  table_count: number;
  total_rows: number;
  total_size_bytes: number;
  size_mb: number;
  size_gb: number;
  size_percentage: number;
  anomaly_count: number;
  health_score: number;
  top_tables: TopTable[];
  purpose_distribution: Record<string, number>;
}

typescript_interfaces.TopTable:
interface TopTable {
  name: string;
  rows: number;
  size_mb: number;
  purpose: string;
}

typescript_interfaces.ModuleDetailResponse:
interface ModuleDetailResponse extends BaseResponse {
  data: {
    module: ModuleInfo;
    statistics: ModuleStatistics;
    tables: TableInfo[];
    anomalies: ModuleAnomalies;
    recommendations: TableRecommendation[];
  };
}

typescript_interfaces.ModuleInfo:
interface ModuleInfo {
  name: string;
  description_th: string;
  description_en: string;
  table_count: number;
  total_rows: number;
  total_size_bytes: number;
  size_mb: number;
  size_gb: number;
  size_percentage: number;
}

typescript_interfaces.ModuleStatistics:
interface ModuleStatistics {
  average_table_size_mb: number;
  largest_table: { name: string; size_mb: number };
  smallest_table: { name: string; size_mb: number };
  empty_tables_count: number;
  tables_over_1m_rows: number;
}

typescript_interfaces.TableInfo:
interface TableInfo {
  name: string;
  row_count: number;
  size_bytes: number;
  size_mb: number;
  size_gb: number;
  engine: string;
  purpose: string;
  severity: 'CRITICAL' | 'WARNING' | 'INFO';
  has_primary_key: boolean;
  index_count: number;
  column_count: number;
  issues: TableIssue[];
}

typescript_interfaces.TableIssue:
interface TableIssue {
  type: string;
  severity: string;
  message: string;
}

typescript_interfaces.ModuleAnomalies:
interface ModuleAnomalies {
  total: number;
  by_severity: { critical: number; warning: number; info: number };
  issues: { table: string; issue: string; severity: string }[];
}

typescript_interfaces.TableRecommendation:
interface TableRecommendation {
  priority: string;
  table: string;
  action: string;
  reason: string;
  sql: string;
}

typescript_interfaces.AnomaliesResponse:
interface AnomaliesResponse extends BaseResponse {
  data: {
    summary: AnomalySummaryDetail;
    categories: AnomalyCategory[];
    severity_distribution: SeverityDistribution;
    priority_actions: PriorityAction[];
  };
}

typescript_interfaces.AnomalySummaryDetail:
interface AnomalySummaryDetail {
  total_anomalies: number;
  critical: number;
  warning: number;
  info: number;
  affected_tables: number;
  health_impact: string;
}

typescript_interfaces.AnomalyCategory:
interface AnomalyCategory {
  name: string;
  display_name: string;
  description: string;
  count: number;
  severity_breakdown: { critical: number; warning: number; info: number };
  percentage_of_total: number;
  recommendation: string;
}

typescript_interfaces.SeverityDistribution:
interface SeverityDistribution {
  critical: { count: number; percentage: number; tables_affected: number };
  warning: { count: number; percentage: number; tables_affected: number };
  info: { count: number; percentage: number; tables_affected: number };
}

typescript_interfaces.PriorityAction:
interface PriorityAction {
  priority: number;
  action: string;
}

typescript_interfaces.AnomalyCategoryResponse:
interface AnomalyCategoryResponse extends BaseResponse {
  pagination: PaginationMeta;
  data: {
    category: AnomalyCategory;
    tables: AnomalyTable[];
  };
}

typescript_interfaces.AnomalyTable:
interface AnomalyTable {
  name: string;
  module: string;
  row_count: number;
  size_bytes: number;
  size_mb: number;
  engine: string;
  severity: string;
  issue: string;
  recommendation: string;
  impact: string;
}

typescript_interfaces.IndexRecommendationsResponse:
interface IndexRecommendationsResponse extends BaseResponse {
  data: {
    summary: {
      total_recommendations: number;
      by_priority: { high: number; medium: number; low: number };
      estimated_impact: { high: string; medium: string; low: string };
    };
    recommendations: IndexRecommendation[];
    by_module: Record<string, { high: number; medium: number; low: number; total: number }>;
    estimated_benefits: { query_performance: string; data_integrity: string; join_performance: string };
  };
}

typescript_interfaces.IndexRecommendation:
interface IndexRecommendation {
  priority: string;
  priority_order: number;
  table: string;
  module: string;
  index_type: string;
  suggested_column: string;
  row_count: number;
  size_mb: number;
  reason: string;
  impact: string;
  sql: string;
}

typescript_interfaces.TablesListResponse:
interface TablesListResponse extends BaseResponse {
  pagination: PaginationMeta;
  data: {
    tables: TableListItem[];
    filters_applied: { module?: string; severity?: string; has_primary_key?: boolean };
    sort: { field: string; order: 'asc' | 'desc' };
  };
}

typescript_interfaces.TableListItem:
interface TableListItem {
  name: string;
  module: string;
  row_count: number;
  size_bytes: number;
  size_mb: number;
  size_gb: number;
  size_human: string;
  engine: string;
  purpose: string;
  has_primary_key: boolean;
  index_count: number;
  column_count: number;
  anomaly_count: number;
  severity: 'CRITICAL' | 'WARNING' | 'INFO';
}

typescript_interfaces.TableDetailResponse:
interface TableDetailResponse extends BaseResponse {
  data: {
    table: TableDetail;
    schema: TableSchema;
    size_context: SizeContext;
    issues: TableIssue[];
    recommendations: TableRecommendation[];
    columns: TableColumn[];
    indexes: TableIndex[];
  };
}

typescript_interfaces.TableDetail:
interface TableDetail {
  name: string;
  module: string;
  row_count: number;
  size: { data_bytes: number; index_bytes: number; total_bytes: number; data_mb: number; index_mb: number; total_mb: number; total_human: string };
  engine: string;
  collation: string;
  purpose: string;
  auto_increment?: number;
  create_time?: string;
  update_time?: string;
  comment?: string;
}

typescript_interfaces.TableSchema:
interface TableSchema {
  column_count: number;
  has_primary_key: boolean;
  index_count: number;
  unique_constraints: number;
  foreign_keys: number;
}

typescript_interfaces.SizeContext:
interface SizeContext {
  rank_in_module: number;
  module_total_size_mb: number;
  percentage_of_module: number;
  database_total_size_mb: number;
  percentage_of_database: number;
}

typescript_interfaces.TableColumn:
interface TableColumn {
  name: string;
  type: string;
  nullable: string;
  key: string;
  default?: string;
  comment?: string;
}

typescript_interfaces.TableIndex:
interface TableIndex {
  name: string;
  columns: string[];
  unique: boolean;
  type: string;
}

typescript_interfaces.SearchResponse:
interface SearchResponse extends BaseResponse {
  data: {
    query: string;
    type: 'tables' | 'modules' | 'columns';
    results: SearchResult[];
    total_count: number;
    search_time_ms: number;
  };
}

typescript_interfaces.SearchResult:
interface SearchResult {
  type: 'table' | 'module' | 'column';
  name: string;
  module?: string;
  row_count?: number;
  size_mb?: number;
  relevance_score: number;
  match_type: 'exact' | 'starts_with' | 'contains';
}
